package org.apache.commons.math3.linear;

import org.junit.runner.RunWith;
import cucumber.api.junit.Cucumber;
import cucumber.api.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math3.linear.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.linear.steps;

import cucumber.api.java.en.Given;
import cucumber.api.java.en.When;
import cucumber.api.java.en.Then;
import org.apache.commons.math3.linear.*;
import org.apache.commons.math3.exception.MathIllegalArgumentException;
import org.apache.commons.math3.exception.NullArgumentException;
import org.apache.commons.math3.exception.DimensionMismatchException;

import java.util.Arrays;

import static org.junit.Assert.*;

public class StepDefs {

    private RealMatrix matrix;
    private RectangularCholeskyDecomposition decomposition;
    private double[][] matrixData;

    @Given("^a (\\d+)x(\\d+) symmetric positive semidefinite matrix \"([^\"]*)\" defined as:$")
    public void a_symmetric_positive_semidefinite_matrix_defined_as(int rows, int cols, String matrixName, java.util.List<java.util.List<String>> table) {
        matrixData = new double[rows][cols];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                matrixData[i][j] = Double.parseDouble(table.get(i).get(j));
            }
        }

        // Create the matrix
        matrix = new Array2DRowRealMatrix(matrixData);
    }

    @When("^I perform a Rectangular Cholesky Decomposition on \"([^\"]*)\" with a threshold of ([\\d\\.e\\-+]+)$")
    public void i_perform_a_Rectangular_Cholesky_Decomposition_on_with_a_threshold_of(String matrixName, double threshold) {
        try {
            decomposition = new RectangularCholeskyDecomposition(matrix, threshold);
        } catch (Exception e) {
            // Capture any exception during decomposition
            throw new RuntimeException("Error during decomposition: " + e.getMessage(), e);
        }
    }

    @Then("^the rebuilt matrix from the decomposition should match \"([^\"]*)\" within a tolerance of ([\\d\\.e\\-+]+)$")
    public void the_rebuilt_matrix_from_the_decomposition_should_match_within_a_tolerance_of(String matrixName, double tolerance) {
        assertTrue("Decomposition should not be null", decomposition != null);

        // Rebuild the matrix from the decomposition
        RealMatrix l = decomposition.getL();
        RealMatrix p = decomposition.getP();

        // Compute L * L^T
        RealMatrix llTranspose = l.multiply(l.transpose());

        // Apply permutation: P^T * (L * L^T) * P
        RealMatrix rebuiltMatrix = p.transpose().multiply(llTranspose.multiply(p));

        // Compare with original matrix
        RealMatrix originalMatrix = matrix;

        for (int i = 0; i < originalMatrix.getRowDimension(); i++) {
            for (int j = 0; j < originalMatrix.getColumnDimension(); j++) {
                double originalValue = originalMatrix.getEntry(i, j);
                double rebuiltValue = rebuiltMatrix.getEntry(i, j);
                assertEquals("Matrix values at [" + i + "][" + j + "] do not match", 
                           originalValue, rebuiltValue, tolerance);
            }
        }
    }

    @Then("^the rank of the decomposition should be (\\d+)$")
    public void the_rank_of_the_decomposition_should_be(int expectedRank) {
        assertTrue("Decomposition should not be null", decomposition != null);
        int actualRank = decomposition.getRank();
        assertEquals("Rank mismatch", expectedRank, actualRank);
    }
}

